function s(n){if(n==null||n==="")return 0;const t=typeof n=="number"?n:Number(n);return Number.isFinite(t)?Math.max(0,Math.floor(t)):0}function c(n){const t=s(n),r=Math.floor(t/60),o=t%60;return{minutes:r,seconds:o}}function f(n){const t=e(n.minutes),r=e(n.seconds,59);return t*60+r}function a(n,t){if(!n.trim())return 0;const r=n.replace(/[^\d]/g,"");if(!r)return 0;const o=Number(r);return Number.isFinite(o)?e(o,t):0}function m(n,t){const r=n.replace(/[^\d]/g,"");return r?String(a(r,t)):""}function u(n){const t=s(n);if(t===0)return"0 secondi";const{minutes:r,seconds:o}=c(t),i=[];return r>0&&i.push(`${r} ${r===1?"minuto":"minuti"}`),o>0&&i.push(`${o} ${o===1?"secondo":"secondi"}`),i.join(" ")}function d(n){return`${u(n)} di recupero`}function b(n){return`${u(n)} di lavoro`}function e(n,t){const r=typeof n=="number"?n:Number(n);if(!Number.isFinite(r))return 0;const o=Math.max(0,Math.floor(r));return typeof t=="number"?Math.min(t,o):o}export{b as a,u as b,c,f as d,d as f,m as s};
